@vex_client.guardrail(
    policy="k12-content-safety",
    max_reading_level="8th_grade",
    bias_detection=True,
    toxicity_threshold=0.1
)
def tutor_response_handler(prompt, session_state):
    """Filter ADK tutor outputs for age-appropriateness"""
    # Vex validates before Gemini generation
    validation = vex_client.validate_education_content(
        prompt,
        grade_level=session_state.get('grade_level'),
        subject=session_state.get('subject')
    )

    if not validation.approved:
        return f"Content blocked: {validation.issues}"

    # Safe execution
    response = gemini_model.generate(prompt)
    return vex_client.sanitize_output(response)
